<template>
	<CommentEntry
		ref="comment"
		tag="li"
		v-bind="comment.props"
		:autoComplete="autoComplete"
		:resourceType="resourceType"
		:message="commentMessage"
		:resourceId="resourceId"
		:userData="genMentionsData(comment.props.mentions)"
		class="comments-activity"
		@delete="reloadCallback()" />
</template>

<script lang="ts">
import type { PropType } from 'vue'

import { t } from '@nextcloud/l10n'
import CommentEntry from '../components/CommentEntry.vue'
import CommentView from '../mixins/CommentView.ts'

export default {
	name: 'ActivityCommentEntry',

	components: {
		CommentEntry,
	},

	mixins: [CommentView],
	props: {
		comment: {
			type: Object,
			required: true,
		},

		reloadCallback: {
			type: Function as PropType<() => void>,
			required: true,
		},
	},

	data() {
		return {
			commentMessage: '',
		}
	},

	watch: {
		comment() {
			this.commentMessage = this.comment.props.message
		},
	},

	mounted() {
		this.commentMessage = this.comment.props.message
	},

	methods: {
		t,
	},
}
</script>

<style scoped>
.comments-activity {
	padding: 0;
}
</style>
